# =============================================================================
# Custom Bootstrap Regression CI Function
# =============================================================================

def bootstrap_regression_ci_custom(X, y, n_bootstrap=1000, confidence_level=0.95, random_state=42):
    """
    Custom bootstrap confidence intervals for regression coefficients.
    
    This function replaces tools.analysis_regression.bootstrap_regression_ci
    due to signature mismatch (expected confidence_level/random_state vs 
    actual seed/alpha parameters).
    
    Returns DataFrame with bootstrap CIs for each predictor.
    """
    np.random.seed(random_state)
    
    # Fit original model
    model = sm.OLS(y, X).fit()
    n_samples, n_predictors = X.shape
    
    # Storage for bootstrap coefficients
    bootstrap_coefs = np.zeros((n_bootstrap, n_predictors))
    
    for i in range(n_bootstrap):
        # Resample with replacement
        indices = np.random.choice(n_samples, size=n_samples, replace=True)
        X_boot = X.iloc[indices] if hasattr(X, 'iloc') else X[indices]
        y_boot = y.iloc[indices] if hasattr(y, 'iloc') else y[indices]
        
        try:
            # Fit bootstrap model
            boot_model = sm.OLS(y_boot, X_boot).fit()
            bootstrap_coefs[i, :] = boot_model.params
        except:
            # If model fails, use original coefficients
            bootstrap_coefs[i, :] = model.params
    
    # Compute confidence intervals
    alpha = 1 - confidence_level
    lower_percentile = (alpha / 2) * 100
    upper_percentile = (1 - alpha / 2) * 100
    
    results = []
    predictor_names = X.columns if hasattr(X, 'columns') else [f'x{i}' for i in range(n_predictors)]
    
    for i, name in enumerate(predictor_names):
        ci_lower = np.percentile(bootstrap_coefs[:, i], lower_percentile)
        ci_upper = np.percentile(bootstrap_coefs[:, i], upper_percentile)
        
        results.append({
            'coefficient': name,
            'mean': bootstrap_coefs[:, i].mean(),
            'std': bootstrap_coefs[:, i].std(),
            'ci_lower': ci_lower,
            'ci_upper': ci_upper
        })
    
    return pd.DataFrame(results)

# =============================================================================
# Statistical Functions
# =============================================================================

def compute_semi_partial_correlation(model, X, y, predictor_idx):
    """
    Compute semi-partial correlation (sr²) for unique variance explained
    by a specific predictor.
    """
    # Get R² of full model
    r2_full = model.rsquared
    
    # Create reduced model without target predictor
    X_reduced = X.drop(X.columns[predictor_idx], axis=1)
    model_reduced = sm.OLS(y, X_reduced).fit()
    r2_reduced = model_reduced.rsquared
    
    # Semi-partial correlation squared
    sr2 = r2_full - r2_reduced
    
    return sr2

def apply_multiple_corrections(p_values, method='bonferroni'):
    """Apply multiple comparison corrections."""
    from statsmodels.stats.multitest import multipletests
    
    if method == 'bonferroni':
        # Manual Bonferroni correction
        return np.minimum(p_values * len(p_values), 1.0)
    elif method == 'fdr':
        # FDR correction using Benjamini-Hochberg
        _, p_corrected, _, _ = multipletests(p_values, method='fdr_bh')
        return p_corrected
    else:
        return p_values

