        # Verify required columns are present
        required_cols = ['UID', 'theta_all', 'dass_dep', 'dass_anx', 'dass_str', 'age', 'nart_score']
        available_cols = df.columns.tolist()
        missing_cols = [col for col in required_cols if col not in available_cols]
        
        if missing_cols:
            raise ValueError(f"Missing required columns: {missing_cols}")
        
        log(f"[CHECK] All required columns present: {available_cols}")

        # =========================================================================
        # STEP 2: Prepare Data for Regression
        # =========================================================================
        # Full model: theta_all ~ age + nart_score + dass_dep + dass_anx + dass_str
        # Target predictors: DASS subscales (depression, anxiety, stress)

        log("[PREP] Preparing regression data...")
        
        # Define predictor order (controls first, then DASS predictors)
        predictor_order = ['age', 'nart_score', 'dass_dep', 'dass_anx', 'dass_str']
        
        # Extract outcome and predictors
        y = df['theta_all']
        X = df[predictor_order].copy()
        
        # Add constant for intercept
        X = sm.add_constant(X)
        
        log(f"[PREP] Full model: {X.shape[1]} predictors (including constant)")
        log(f"[PREP] Sample size: N = {len(y)}")
        
        # Check for missing data
        missing_data = X.isnull().sum().sum() + y.isnull().sum()
        if missing_data > 0:
            log(f"[WARNING] {missing_data} missing values detected")
            # Remove cases with any missing data
            complete_mask = X.isnull().sum(axis=1) == 0
            complete_mask = complete_mask & (~y.isnull())
            X = X[complete_mask]
            y = y[complete_mask]
            log(f"[PREP] After listwise deletion: N = {len(y)}")

        # =========================================================================
        # STEP 3: Fit Full Regression Model
        # =========================================================================
        # Full model with all controls and DASS predictors
        # Extract coefficients, standard errors, and t-statistics

        log("[ANALYSIS] Fitting full regression model...")
        full_model = sm.OLS(y, X).fit()
        
        # Model summary
        log(f"[MODEL] R² = {full_model.rsquared:.4f}, Adjusted R² = {full_model.rsquared_adj:.4f}")
        log(f"[MODEL] F({full_model.df_model}, {full_model.df_resid}) = {full_model.fvalue:.3f}, p = {full_model.f_pvalue:.4f}")
        
        # Check for multicollinearity (VIF for predictors only, not constant)
        X_predictors = X.drop('const', axis=1)
        vif_data = []
        for i, col in enumerate(X_predictors.columns):
            vif = variance_inflation_factor(X_predictors.values, i)
            vif_data.append({'predictor': col, 'VIF': vif})
            log(f"[VIF] {col}: {vif:.2f}")
        
        # Flag high VIF values
        high_vif = [item for item in vif_data if item['VIF'] > 5.0]
        if high_vif:
            log(f"[WARNING] High multicollinearity detected: {high_vif}")

        # =========================================================================
        # STEP 4: Extract DASS Predictor Effects
        # =========================================================================
        # Focus on dass_dep, dass_anx, dass_str coefficients
        # Compute semi-partial correlations (unique variance explained)

        log("[EXTRACT] Extracting individual DASS predictor effects...")
        
        target_predictors = ['dass_dep', 'dass_anx', 'dass_str']
        predictor_results = []
        
        for predictor in target_predictors:
            # Find index in model (accounting for constant)
            predictor_idx = list(X.columns).index(predictor)
            
            # Extract basic statistics
            beta = full_model.params[predictor_idx]
            se = full_model.bse[predictor_idx] 
            t_stat = full_model.tvalues[predictor_idx]
            p_uncorrected = full_model.pvalues[predictor_idx]
            
            # Compute semi-partial correlation (unique variance)
            # Find index in X_predictors (without constant)
            predictor_idx_no_const = list(X_predictors.columns).index(predictor)
            sr2 = compute_semi_partial_correlation(full_model, X_predictors, y, predictor_idx_no_const)
            
            predictor_results.append({
                'predictor': predictor,
                'beta': beta,
                'se': se,
                't_stat': t_stat,
                'sr2': sr2,
                'p_uncorrected': p_uncorrected
            })
            
            log(f"[PREDICTOR] {predictor}: β = {beta:.4f}, t = {t_stat:.3f}, sr² = {sr2:.4f}, p = {p_uncorrected:.4f}")

        # =========================================================================
        # STEP 5: Bootstrap Confidence Intervals
        # =========================================================================
        # Use custom bootstrap implementation due to signature mismatch
        # 1000 bootstrap iterations for robust CIs

        log("[BOOTSTRAP] Computing bootstrap confidence intervals (1000 iterations)...")
        
        # Bootstrap CIs for all predictors (we'll extract DASS predictors later)
        bootstrap_results = bootstrap_regression_ci_custom(
            X, y, 
            n_bootstrap=1000, 
            confidence_level=0.95, 
            random_state=42
        )
        
        # Extract CIs for target predictors
        for i, predictor in enumerate(target_predictors):
            bootstrap_row = bootstrap_results[bootstrap_results['coefficient'] == predictor]
            if len(bootstrap_row) > 0:
                ci_lower = bootstrap_row.iloc[0]['ci_lower']
                ci_upper = bootstrap_row.iloc[0]['ci_upper']
                predictor_results[i]['ci_lower'] = ci_lower
                predictor_results[i]['ci_upper'] = ci_upper
                
                log(f"[BOOTSTRAP] {predictor}: 95% CI [{ci_lower:.4f}, {ci_upper:.4f}]")
            else:
                log(f"[WARNING] No bootstrap CI found for {predictor}")
                predictor_results[i]['ci_lower'] = np.nan
                predictor_results[i]['ci_upper'] = np.nan

        # =========================================================================
        # STEP 6: Apply Multiple Comparison Corrections (Decision D068)
        # =========================================================================
        # Bonferroni correction: α = 0.00179/3 = 0.00060 per test
        # FDR correction: Benjamini-Hochberg procedure
        # Dual p-value reporting per Decision D068

        log("[CORRECTION] Applying multiple comparison corrections (Decision D068)...")
        
        # Extract uncorrected p-values for DASS predictors
        p_values_uncorrected = [result['p_uncorrected'] for result in predictor_results]
        
        # Bonferroni correction
        p_values_bonferroni = apply_multiple_corrections(p_values_uncorrected, method='bonferroni')
        
        # FDR correction
        p_values_fdr = apply_multiple_corrections(p_values_uncorrected, method='fdr')
        
        # Add corrected p-values to results
        for i, result in enumerate(predictor_results):
            result['p_bonferroni'] = p_values_bonferroni[i]
            result['p_fdr'] = p_values_fdr[i]
            
            log(f"[CORRECTION] {result['predictor']}:")
            log(f"    p_uncorrected = {result['p_uncorrected']:.6f}")
            log(f"    p_bonferroni = {result['p_bonferroni']:.6f}")  
            log(f"    p_fdr = {result['p_fdr']:.6f}")
        
        # Apply Chapter 7 Bonferroni threshold (α = 0.00060 per test)
        chapter7_alpha = 0.00179 / 3  # = 0.00060
        significant_bonferroni = [result for result in predictor_results 
                                if result['p_bonferroni'] < chapter7_alpha]
        
        log(f"[SIGNIFICANCE] Significant predictors (Bonferroni α = {chapter7_alpha:.6f}): {len(significant_bonferroni)}")
        for result in significant_bonferroni:
            log(f"    {result['predictor']}: p_bonferroni = {result['p_bonferroni']:.6f}")

        # =========================================================================
        # STEP 7: Save Individual Predictor Results
        # =========================================================================
        # Main output: CSV with individual DASS predictor effects and dual p-values

        log("[SAVE] Saving individual predictor results...")
        
