            f.write("FDR Correction:\n")
            f.write(f"  Method: Benjamini-Hochberg procedure\n")
            f.write(f"  Controls False Discovery Rate at 5%\n\n")
            f.write("RESULTS SUMMARY:\n")
            for result in predictor_results:
                f.write(f"\n{result['predictor']}:\n")
