                f.write(f"  p_uncorrected = {result['p_uncorrected']:.6f}\n")
                f.write(f"  p_bonferroni = {result['p_bonferroni']:.6f}\n")
                f.write(f"  p_fdr = {result['p_fdr']:.6f}\n")
                
